819	/// C: `int luaD_pretailcall(lua_State *L, CallInfo *ci, StkId func, int narg1, int delta)`
820	pub(crate) fn pretailcall(
821	    state: &mut LuaState,
822	    ci_idx: CallInfoIdx,
823	    mut func_idx: StackIdx,
824	    mut narg1: i32,
825	    delta: i32,
826	) -> Result<i32, LuaError> {
