829	        let func_val = state.get_at(func_idx).clone();
830	        match func_val {
831	            // C: case LUA_VCCL — return precallC(L, func, LUA_MULTRET, clCvalue(s2v(func))->f);
832	            LuaValue::Function(LuaClosure::C(ref cl)) => {
833	                let cfunc = state.global().c_functions[cl.func];
834	                return precall_c(state, func_idx, LUA_MULTRET, cfunc);
835	            }
836	            // C: case LUA_VLCF — return precallC(L, func, LUA_MULTRET, fvalue(s2v(func)));
