840	            }
841	            // C: case LUA_VLCL — Lua function
842	            LuaValue::Function(LuaClosure::Lua(ref cl)) => {
843	                let proto = cl.proto.clone();
844	                let fsize = proto.maxstacksize as i32;
845	                let nfixparams = proto.numparams as i32;
